On FreeBSD 7.0R, when shutdown(2) called with SHUT_RD or SHUT_RDWR against 
an one-to-one SCTP socket, sbdrop_internel() called.
However, sbdrop_internel() assumes that the receiver socket buffer is one for not SCTP.
In the case of SCTP, sb_mb is always null (not used).
So, sbdrop_internel() will panic at sys/kern/uipc_sockbuf.c[849].

Fix: The below patch is for FreeBSD 7.0-RELEASE.
How-To-Repeat: The below very simple codes will trigger panic ....

==
% cat > client.c
#include <sys/types.h>
#include <sys/socket.h>

#include <netinet/in.h>

#include <stdio.h>
#include <string.h>
#include <err.h>

int main(int argc, char **argv)
{

	int sfd;
	struct sockaddr_in sin;

	sfd = socket(AF_INET, SOCK_STREAM, IPPROTO_SCTP);
	if (sfd < 0) {
		err(1, "socket");
	}

	memset(&sin, 0, sizeof(sin));
	sin.sin_family = AF_INET;
	sin.sin_len = sizeof(sin);
	sin.sin_addr.s_addr = inet_addr("127.0.0.1");
	sin.sin_port = htons(10001);

	if (connect(sfd, (struct sockaddr *)&sin, sizeof(sin)) < 0) {
		err(1, "connect");
	}

	write(sfd, "foo", sizeof("foo"));

	close(sfd);
	return 0;
}

% gcc -o client client.c
% cat > server.c
#include <sys/types.h>
#include <sys/socket.h>

#include <netinet/in.h>

#include <stdio.h>
#include <string.h>
#include <err.h>

int main(int argc, char **argv)
{

	int sfd, sfd1;
	struct sockaddr_in sin, addr;
	socklen_t addrlen;
	char buf[4096];
	int len;

	sfd = socket(AF_INET, SOCK_STREAM, IPPROTO_SCTP);
	if (sfd < 0) {
		err(1, "socket");
	}

	memset(&sin, 0, sizeof(sin));
	sin.sin_family = AF_INET;
	sin.sin_len = sizeof(sin);
	sin.sin_addr.s_addr = inet_addr("127.0.0.1");
	sin.sin_port = htons(10001);

	if (bind(sfd, (struct sockaddr *)&sin, sizeof(sin)) < 0) {
		err(1, "bind");
	}

	if (listen(sfd, 1) < 0) {
		err(1, "listen");
	}

	addrlen = sizeof(addr);
	sfd1 = accept(sfd, (struct sockaddr *)&addr, &addrlen);
	if (sfd1 < 0) {
		err(1, "accept");
	}

	sleep(1);
	if (shutdown(sfd1, SHUT_RD) < 0) {
		err(1, "shutdown");
	}

	len = read(sfd1, buf, sizeof(buf));
	if (len < 0) {
		err(1, "read");
	}
	printf("len=%d\n", len);

	close(sfd1);
	close(sfd);
	return 0;
}
% gcc -o server server.c
% ./server&
% ./client
